import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, Link } from "react-router-dom";
import {
  getB2bProducts, submitRfq, resetB2bState, getB2bProfile,
} from "../../features/b2b/b2bSlice";
import B2bLayout from "./B2bLayout";
import {
  Plus, Trash2, Calendar, FileText, Send, AlertTriangle,
  ArrowLeft, Loader2, Package, ChevronRight, Info,
  ChevronDown, ChevronUp,
} from "lucide-react";

/* ─────────────────────────────────────────────────────────────
   Primitives
───────────────────────────────────────────────────────────── */
const Card = ({ className = "", children }) => (
  <div className={`bg-white border border-slate-200/80 rounded-xl shadow-sm ${className}`}>
    {children}
  </div>
);
const CardHeader = ({ children, className = "" }) => (
  <div className={`px-5 py-3.5 border-b border-slate-100 ${className}`}>{children}</div>
);
const CardBody = ({ children, className = "" }) => (
  <div className={`px-5 py-4 ${className}`}>{children}</div>
);
const Label = ({ children, required }) => (
  <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-widest mb-1.5">
    {children}{required && <span className="text-red-400 ml-0.5">*</span>}
  </label>
);
const inputCls =
  "w-full h-10 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all";

/* ─────────────────────────────────────────────────────────────
   Inline HTML product description (safe subset)
───────────────────────────────────────────────────────────── */
const ProductDescription = ({ html }) => {
  const [open, setOpen] = useState(false);
  if (!html) return null;
  return (
    <div className="mt-2">
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="inline-flex items-center gap-1 text-[11px] font-semibold text-blue-600 hover:text-blue-700 transition-colors"
      >
        {open ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
        {open ? "Hide description" : "View product description"}
      </button>
      {open && (
        <div
          className="mt-2 p-3 bg-slate-50 border border-slate-100 rounded-lg text-[12px] text-slate-600 leading-relaxed
            prose prose-sm max-w-none
            prose-headings:font-semibold prose-headings:text-slate-800
            prose-strong:font-semibold prose-strong:text-slate-800
            prose-ul:list-disc prose-ul:pl-4 prose-li:my-0.5
            prose-p:my-1"
          dangerouslySetInnerHTML={{ __html: html }}
        />
      )}
    </div>
  );
};

/* ─────────────────────────────────────────────────────────────
   Single product line row
───────────────────────────────────────────────────────────── */
const LineRow = ({ item, index, products, onRemove, onChange, canRemove }) => {
  const selectedProduct = products?.find((p) => p.id === item.productId);

  return (
    <div className="relative">
      <div className="bg-slate-50 border border-slate-200/60 rounded-xl p-4">
        {/* Row number badge */}
        <div className="flex items-center justify-between mb-3">
          <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-slate-200 text-slate-600 text-[10px] font-bold">
            {index + 1}
          </span>
          {canRemove && (
            <button
              type="button"
              onClick={() => onRemove(index)}
              className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
            >
              <Trash2 size={14} />
            </button>
          )}
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-12 gap-3">
          {/* Catalog product select — spans 5 cols */}
          <div className="sm:col-span-5">
            <Label>Catalog Product</Label>
            <select
              value={item.productId}
              onChange={(e) => onChange(index, "productId", e.target.value)}
              className={`${inputCls} cursor-pointer`}
            >
              <option value="">Select from catalog…</option>
              {products?.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.title}{p.sku ? ` (${p.sku})` : ""}
                </option>
              ))}
            </select>

            {/* Show description if a product is selected */}
            {selectedProduct && (
              <ProductDescription
                html={
                  selectedProduct.description ||
                  selectedProduct.longDescription ||
                  selectedProduct.details ||
                  null
                }
              />
            )}
          </div>

          {/* OR generic name — spans 3 cols */}
          <div className="sm:col-span-3">
            <Label>Or Specify by Name</Label>
            <input
              type="text"
              placeholder="e.g. Paracetamol 500mg"
              value={item.genericName}
              onChange={(e) => onChange(index, "genericName", e.target.value)}
              className={inputCls}
            />
            <p className="text-[10px] text-slate-400 mt-1">Leave blank if catalog product selected</p>
          </div>

          {/* Quantity — spans 2 cols */}
          <div className="sm:col-span-2">
            <Label required>Quantity</Label>
            <input
              type="number"
              min="1"
              value={item.quantity}
              onChange={(e) => onChange(index, "quantity", e.target.value)}
              className={`${inputCls} text-center`}
              required
            />
          </div>

          {/* Target price — spans 2 cols */}
          <div className="sm:col-span-2">
            <Label>Target Price</Label>
            <div className="relative">
              <input
                type="number"
                step="0.01"
                placeholder="0.00"
                value={item.targetPrice}
                onChange={(e) => onChange(index, "targetPrice", e.target.value)}
                className={`${inputCls} pr-10`}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-[11px] text-slate-400 font-medium pointer-events-none">
                ETB
              </span>
            </div>
          </div>
        </div>

        {/* Validation hint */}
        {!item.productId && !item.genericName && (
          <p className="mt-2 flex items-center gap-1 text-[11px] text-amber-600">
            <Info size={11} className="shrink-0" />
            Select a catalog product or enter a generic name
          </p>
        )}
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────────────────────
   Main page
───────────────────────────────────────────────────────────── */
const B2bRfqSubmit = () => {
  const dispatch  = useDispatch();
  const navigate  = useNavigate();
  const { products, profile, isLoading, isSuccess, isError, message } =
    useSelector((s) => s.b2b);

  const [items, setItems] = useState([
    { productId: "", quantity: 1, targetPrice: "", genericName: "" },
  ]);
  const [requiredDate, setRequiredDate] = useState("");
  const [notes,        setNotes       ] = useState("");
  const [submitted,    setSubmitted   ] = useState(false);

  useEffect(() => {
    dispatch(getB2bProducts({ limit: 200 }));
    dispatch(getB2bProfile());
  }, [dispatch]);

  useEffect(() => {
    if (isSuccess && submitted) {
      dispatch(resetB2bState());
      navigate("/b2b/rfq");
    }
  }, [isSuccess, submitted, dispatch, navigate]);

  const addLine  = () =>
    setItems((p) => [...p, { productId: "", quantity: 1, targetPrice: "", genericName: "" }]);
  const removeLine = (i) =>
    setItems((p) => p.filter((_, idx) => idx !== i));
  const changeLine = (i, field, val) =>
    setItems((p) => p.map((it, idx) => (idx === i ? { ...it, [field]: val } : it)));

  const handleSubmit = (e) => {
    e.preventDefault();
    const payload = {
      items: items.map((it) => ({
        productId:   it.productId   || undefined,
        quantity:    parseInt(it.quantity)        || 1,
        targetPrice: it.targetPrice ? parseFloat(it.targetPrice) : undefined,
        genericName: it.genericName || undefined,
      })),
      requiredDate: requiredDate || undefined,
      notes:        notes        || undefined,
    };
    setSubmitted(true);
    dispatch(submitRfq(payload));
  };

  const validItems = items.filter((it) => it.productId || it.genericName);
  const canSubmit  = !isLoading && validItems.length > 0 && profile?.isVerified;

  return (
    <B2bLayout>

      {/* ── Breadcrumb ── */}
      <nav className="flex items-center gap-1.5 text-[12px] text-slate-400 font-medium mb-7">
        <Link to="/b2b/rfq" className="flex items-center gap-1 hover:text-blue-600 transition-colors">
          <ArrowLeft size={13} /> RFQ Submissions
        </Link>
        <ChevronRight size={13} className="text-slate-300" />
        <span className="text-slate-700">New Request</span>
      </nav>

      {/* ── Page header ── */}
      <div className="mb-7">
        <h1 className="text-[22px] font-bold text-slate-900 tracking-tight">Request For Quote (RFQ)</h1>
        <p className="text-[13px] text-slate-500 mt-1">
          Request pricing for catalog products or custom items not yet in the catalog.
        </p>
      </div>

      {/* ── Verification banner ── */}
      {profile && !profile.isVerified && (
        <div className="mb-6 flex items-start gap-3 p-4 bg-amber-50 border border-amber-200 rounded-xl">
          <AlertTriangle size={16} className="text-amber-500 shrink-0 mt-0.5" />
          <div>
            <p className="text-[13px] font-semibold text-amber-900">Account Pending Verification</p>
            <p className="text-[12px] text-amber-700 mt-0.5">
              RFQ submissions are available to verified B2B accounts only. Your account is under review.
            </p>
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

          {/* ═══ LEFT — Line items ══════════════════════════ */}
          <div className="lg:col-span-2 flex flex-col gap-4">
            <Card>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-[12px] font-semibold text-slate-700">
                      Requested Products &amp; Quantities
                    </p>
                    <p className="text-[11px] text-slate-400 mt-0.5">
                      {items.length} line{items.length !== 1 ? "s" : ""}
                      {validItems.length < items.length && (
                        <span className="text-amber-500 ml-1.5">
                          · {items.length - validItems.length} incomplete
                        </span>
                      )}
                    </p>
                  </div>
                  <span className="text-[10px] font-semibold text-slate-400 uppercase tracking-widest hidden sm:block">
                    Product / Name · Qty · Target Price
                  </span>
                </div>
              </CardHeader>

              <CardBody className="flex flex-col gap-3">
                {items.map((item, i) => (
                  <LineRow
                    key={i}
                    index={i}
                    item={item}
                    products={products}
                    onRemove={removeLine}
                    onChange={changeLine}
                    canRemove={items.length > 1}
                  />
                ))}

                {/* Add line button */}
                <button
                  type="button"
                  onClick={addLine}
                  className="mt-1 flex items-center gap-2 h-10 px-4 w-full border-2 border-dashed border-slate-200 rounded-xl text-[13px] font-medium text-slate-400 hover:border-blue-400 hover:text-blue-600 hover:bg-blue-50/40 transition-all"
                >
                  <Plus size={15} />
                  Add Product Line
                </button>
              </CardBody>
            </Card>

            {/* Custom / Off-catalog note */}
            <div className="flex items-start gap-3 p-4 bg-blue-50 border border-blue-100 rounded-xl">
              <Package size={16} className="text-blue-500 shrink-0 mt-0.5" />
              <div>
                <p className="text-[12px] font-semibold text-blue-800">Need something not in the catalog?</p>
                <p className="text-[12px] text-blue-700 mt-0.5">
                  Leave the "Catalog Product" field blank and enter the product name, specification, or generic name.
                  Our team will source it and respond with a custom quote.
                </p>
              </div>
            </div>
          </div>

          {/* ═══ RIGHT — RFQ meta + submit ══════════════════ */}
          <div className="lg:col-span-1">
            <div className="lg:sticky lg:top-[96px] flex flex-col gap-4">

              <Card>
                <CardHeader>
                  <p className="text-[11px] font-semibold text-slate-500 uppercase tracking-widest">RFQ Details</p>
                </CardHeader>
                <CardBody className="flex flex-col gap-4">

                  {/* Required date */}
                  <div>
                    <Label>Required Delivery Date</Label>
                    <div className="relative">
                      <Calendar size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                      <input
                        type="date"
                        value={requiredDate}
                        onChange={(e) => setRequiredDate(e.target.value)}
                        className={`${inputCls} pl-9`}
                      />
                    </div>
                  </div>

                  {/* Notes */}
                  <div>
                    <Label>Procurement Notes</Label>
                    <textarea
                      value={notes}
                      onChange={(e) => setNotes(e.target.value)}
                      placeholder="Specifications, certifications, regulatory requirements, batch requirements…"
                      rows={4}
                      className="w-full px-3 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all resize-none"
                    />
                  </div>

                </CardBody>
              </Card>

              {/* Summary card */}
              <Card>
                <CardBody>
                  <div className="flex items-center justify-between mb-3">
                    <p className="text-[11px] font-semibold text-slate-500 uppercase tracking-widest">Summary</p>
                  </div>
                  <div className="space-y-2 text-[12px]">
                    <div className="flex justify-between">
                      <span className="text-slate-500">Total lines</span>
                      <span className="font-semibold text-slate-800">{items.length}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-slate-500">Catalog items</span>
                      <span className="font-semibold text-slate-800">
                        {items.filter((i) => i.productId).length}
                      </span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-slate-500">Custom items</span>
                      <span className="font-semibold text-slate-800">
                        {items.filter((i) => !i.productId && i.genericName).length}
                      </span>
                    </div>
                    {requiredDate && (
                      <div className="flex justify-between">
                        <span className="text-slate-500">Delivery by</span>
                        <span className="font-semibold text-slate-800">
                          {new Date(requiredDate).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                        </span>
                      </div>
                    )}
                  </div>
                </CardBody>
              </Card>

              {/* Error */}
              {isError && (
                <div className="flex items-start gap-2 p-3 bg-red-50 border border-red-200 rounded-xl text-[12px] text-red-700">
                  <AlertTriangle size={14} className="shrink-0 mt-0.5" />
                  {typeof message === "string" ? message : "Failed to submit RFQ. Please try again."}
                </div>
              )}

              {/* Submit */}
              <button
                type="submit"
                disabled={!canSubmit}
                className={`w-full h-11 rounded-lg text-[13px] font-semibold flex items-center justify-center gap-2 transition-all ${
                  !canSubmit
                    ? "bg-slate-100 text-slate-400 cursor-not-allowed"
                    : "bg-slate-900 hover:bg-blue-600 text-white active:scale-[0.98]"
                }`}
              >
                {isLoading
                  ? <><Loader2 size={15} className="animate-spin" /> Submitting…</>
                  : <><Send size={15} /> Submit RFQ Request</>
                }
              </button>

              {!profile?.isVerified && (
                <p className="text-center text-[11px] text-slate-400">
                  Verified accounts only — your account is under review
                </p>
              )}
            </div>
          </div>

        </div>
      </form>
    </B2bLayout>
  );
};

export default B2bRfqSubmit;
